const query = $json.query || {};

// Paginação
const limit = parseInt(query.limit) || 10;
const page = parseInt(query.page) || 1;
const offset = (page - 1) * limit;

// Search (Tratamento para busca parcial LIKE)
const search = query.search ? `%${query.search}%` : null;
const status = query.status || null;
const date = query.date || null;

return {
  search: query.search ? `%${query.search}%` : null,
  status: query.status || null,
  date: query.date || null,
  limit: parseInt(query.limit) || 10,
  offset: (parseInt(query.page || 1) - 1) * (parseInt(query.limit) || 10)
};

const items = $input.all();
if (items.length === 0) return { data: [], pagination: { total: 0 } };

const total = parseInt(items[0].json.total_count);
const limit = $("PREPARE_QUERY").first().json.limit;
const page = $("PREPARE_QUERY").first().json.page;

return {
  data: items.map(i => {
    delete i.json.total_count; // Remove o contador de cada linha
    return i.json;
  }),
  pagination: {
    total_items: total,
    total_pages: Math.ceil(total / limit),
    current_page: page,
    limit: limit
  }
};
